input.new_string:
// Tip label placement, in pixel space, not polar: push a touch past the
// tip along the arrow's own direction, then sideways, perpendicular to it.
// Candidates use side=1, the probe uses side=-1, so even when the probe
// sweeps exactly onto a candidate's angle the two labels land on
// opposite sides of the shared line and never collide.
function tipLabel(x: number, y: number, side: 1 | -1) {
	const tip = pt(x, y);
	const dx = tip.px - CX;
	const dy = tip.py - CY;
	const mag = Math.hypot(dx, dy) || 1;
	const ux = dx / mag;
	const uy = dy / mag;
	const perpx = -uy;
	const perpy = ux;
	const px = tip.px + ux * 12 + perpx * 17 * side;
	const py = tip.py + uy * 12 + perpy * 17 * side;
	return { px: cl(px), py: Math.min(Math.max(py, 14), S - 8) };
}

