content.content:
1	<script lang="ts">
2		// DotMeter v2 — the judge's hand-built take, for direct iteration with Jake.
3		// The design thesis: multiply-and-add should be VISIBLE, not narrated.
4		// Every bar is literally its two products stacked; the strip below shows
5		// the arithmetic for whichever candidate you select, live, to two decimals.
6	
7		// The two entries mean something: x is how loud, y is how fast.
8		const CANDIDATES = [
9			{ id: 'c1', name: 'Night Drive', angle: 20 },
10			{ id: 'c2', name: 'Glass Rain', angle: 70 },
11			{ id: 'c3', name: 'Slow Burn', angle: 110 },
12			{ id: 'c4', name: 'Static', angle: 160 }
13		];
14	
15		let challenge = $state<null | 'cheat' | 'short'>(null);
16		let solvedCheat = $state(false);
17		let solvedShort = $state(false);
18		const WHY = {
19			cheat:
20				'A song that is simply louder and faster everywhere piles up score without matching your mix. A raw meter overrates intense tracks, so a recommender built on it keeps pushing whatever is biggest.',
21			short:
22				'A quiet song that matches your mix exactly gets buried under bigger ones. Size is drowning direction, and fixing that is exactly where this lesson is headed.'
23		};
24		function startChallenge(kind: 'cheat' | 'short') {
25			// one click always re-arms: a solved card resets on first click,
26			// whether or not another challenge was active in between
27			if (kind === 'cheat' && (challenge === 'cheat' || solvedCheat)) solvedCheat = false;
28			if (kind === 'short' && (challenge === 'short' || solvedShort)) solvedShort = false;
29			challenge = kind;
30			probeAngle = 40;
31			lengthC1 = 1.0;
32			selected = 'c1';
33		}
34		$effect(() => {
35			if (challenge === 'cheat' && cheatActive) solvedCheat = true;
36			if (challenge === 'short' && shortChanged) solvedShort = true;
37		});
38	
39		let probeAngle = $state(40);
40		let lengthC1 = $state(1.0);
41		let selected = $state('c1');
42		let hovered = $state<string | null>(null);
43		let dragging = $state<'probe' | 'length' | null>(null);
44	
45		const rad = (d: number) => (d * Math.PI) / 180;
46	
47		const probe = $derived({ x: Math.cos(rad(probeAngle)), y: Math.sin(rad(probeAngle)) });
48	
49		const rows = $derived(
50			CANDIDATES.map((c) => {
51				const len = c.id === 'c1' ? lengthC1 : 1;
52				const x = len * Math.cos(rad(c.angle));
53				const y = len * Math.sin(rad(c.angle));
54				const px = probe.x * x; // the x-term product
55				const py = probe.y * y; // the y-term product
56				const score = px + py;
57				// r1 is the score at the SAME one-decimal precision the meter
58				// displays, so leader/tie judgments always match what's on screen.
59				const r1 = Number((Object.is(score, -0) ? 0 : score).toFixed(1));
60				return { ...c, len, x, y, px, py, score, r1 };
61			})
62		);
63	
64		const maxR1 = $derived(Math.max(...rows.map((r) => r.r1)));
65		const leaders = $derived(rows.filter((r) => r.r1 === maxR1).map((r) => r.id));
66		const tied = $derived(leaders.length > 1);
67		const sel = $derived(rows.find((r) => r.id === selected) ?? rows[0]);
68	
69		// The mirror lesson: c1 aims truest but is too short to win.
70		const shortChanged = $derived.by(() => {
71			const c1 = rows[0];
72			if (lengthC1 >= 0.95 || leaders.includes('c1')) return false;
73			return rows.every(
74				(r) =>
75					r.id === 'c1' ||
76					Math.abs(((r.angle - probeAngle + 540) % 360) - 180) >
77						Math.abs(((c1.angle - probeAngle + 540) % 360) - 180)
78			);
79		});
80	
81		// The overtake: c1 stretched AND outscoring a candidate that out-aligns it.
82		// Returns the most deserving victim (best-aligned beaten song) so the flag
83		// can name the exact pair instead of making a vague claim about the board.
84		const cheatVictim = $derived.by(() => {
85			const c1 = rows[0];
86			if (lengthC1 <= 1.05) return null;
87			const dist = (angle: number) => Math.abs(((angle - probeAngle + 540) % 360) - 180);
88			const beaten = rows.filter(
89				(r) => r.id !== 'c1' && dist(r.angle) < dist(c1.angle) && c1.r1 > r.r1
90			);
91			if (beaten.length === 0) return null;
92			return beaten.reduce((a, b) => (dist(a.angle) < dist(b.angle) ? a : b));
93		});
94		const cheatActive = $derived(cheatVictim !== null);
95		const leaderName = $derived(rows.find((r) => r.id === leaders[0])?.name ?? '');
96	
97		// --- Arena geometry (SVG units) ---
98		const S = 400; // viewBox square
99		const CX = S / 2;
100		const CY = S / 2;
101		const R = 92; // unit arrow length in px; 2.0 x R stays inside the frame
102		const pt = (x: number, y: number) => ({ px: CX + x * R, py: CY - y * R });
103	
104		function arrow(x: number, y: number) {
105			const tip = pt(x, y);
106			const ang = Math.atan2(CY - tip.py, tip.px - CX);
107			const L = Math.hypot(tip.px - CX, tip.py - CY);
108			const head = Math.max(7, Math.min(11, L * 0.09));
109			const back = { px: tip.px - head * Math.cos(ang), py: tip.py + head * Math.sin(ang) };
110			const left = {
111				px: back.px - head * 0.55 * Math.sin(ang),
112				py: back.py - head * 0.55 * Math.cos(ang)
113			};
114			const right = {
115				px: back.px + head * 0.55 * Math.sin(ang),
116				py: back.py + head * 0.55 * Math.cos(ang)
117			};
118			return {
119				shaft: { x1: CX, y1: CY, x2: back.px, y2: back.py },
120				head: `${tip.px},${tip.py} ${left.px},${left.py} ${right.px},${right.py}`
121			};
122		}
123	
124		// Tip label placement, in pixel space, not polar: push a touch past the
125		// tip along the arrow's own direction, then sideways, perpendicular to
126		// it. Candidates and the probe pass opposite `side` values, so even when
127		// the probe sweeps exactly onto a candidate's angle the two labels land
128		// on opposite sides of the shared line and never collide.
129		function tipLabel(x: number, y: number, side: 1 | -1) {
130			const tip = pt(x, y);
131			const dx = tip.px - CX;
132			const dy = tip.py - CY;
133			const mag = Math.hypot(dx, dy) || 1;
134			const ux = dx / mag;
135			const uy = dy / mag;
136			const perpx = -uy;
137			const perpy = ux;
138			const px = tip.px + ux * 12 + perpx * 17 * side;
139			const py = tip.py + uy * 12 + perpy * 17 * side;
140			return { px: cl(px), py: Math.min(Math.max(py, 14), S - 8) };
141		}
142	
143		let arenaEl = $state<SVGSVGElement | null>(null);
144	
145		function anglesFromEvent(e: PointerEvent) {
146			if (!arenaEl) return null;
147			const r = arenaEl.getBoundingClientRect();
148			const x = ((e.clientX - r.left) / r.width) * S - CX;
149			const y = CY - ((e.clientY - r.top) / r.height) * S;
150			return { angle: ((Math.atan2(y, x) * 180) / Math.PI + 360) % 360, dist: Math.hypot(x, y) / R };
151		}
152	
153		function onArenaPointer(e: PointerEvent) {
154			const a = anglesFromEvent(e);
155			if (!a || !dragging) return;
156			if (dragging === 'probe') probeAngle = Math.round(a.angle / 5) * 5 % 360;
157			else lengthC1 = Math.max(0.5, Math.min(2, Math.round(a.dist * 10) / 10));
158		}
159	
